frappe.ui.form.on("Job Quote", {
    refresh(frm) {
        update_all_task_labels(frm);
    },

    // listen to any task field change dynamically
    task1_name(frm) { update_task_label(frm, 1); },
    task2_name(frm) { update_task_label(frm, 2); },
    task3_name(frm) { update_task_label(frm, 3); },
    task4_name(frm) { update_task_label(frm, 4); },
    task5_name(frm) { update_task_label(frm, 5); },
});

// loop through all tasks
function update_all_task_labels(frm) {
    for (let i = 1; i <= 5; i++) {
        update_task_label(frm, i);
    }
}

function update_task_label(frm, taskNum) {
    let field_name = `task${taskNum}_name`;
    let section_fieldname = `task_${taskNum}_section`;
    let value = frm.doc[field_name] || `Task ${taskNum}`;
    let label_text = `Task${taskNum} - ${value}`;

    // Update metadata
    frm.set_df_property(section_fieldname, "label", label_text);

    // Force UI update without breaking arrow
    setTimeout(() => {
        let section = frm.fields_dict[section_fieldname];
        if (section && section.wrapper) {
            let header = $(section.wrapper).find(".section-head");

            // Remove old text nodes
            header.contents().filter(function() {
                return this.nodeType === 3;
            }).remove();

            // Insert new label after the arrow
            let arrow = header.find(".caret");
            if (arrow.length) {
                arrow.after(" " + label_text);
            } else {
                header.prepend(label_text + " ");
            }
        }
    }, 50);
}

