frappe.ui.form.on("Vehicle Purchase Order", {
    job_quote(frm) {
        if (!frm.doc.job_quote) return;

        frappe.call({
            method: "vehicle.vehicle.doctype.vehicle_purchase_order.vehicle_purchase_order.get_job_quote",
            args: {
                source_name: frm.doc.job_quote
            },
            callback: function(r) {
                if (r.message) {
                    // clear all tables first
                    for (let i = 1; i <= 10; i++) {
                        frm.clear_table(`table_${i}`);
                    }

                    // set all values from server
                    frm.set_value(r.message);

                    frm.refresh();
                }
            }
        });
    }
});

frappe.ui.form.on("GRV", {
    grv(frm) {
        if (!frm.doc.purchase_order) return;

        frappe.call({
            method: "vehicle.vehicle.doctype.grv.grv.get_vehicle_order",
            args: {
                source_name: frm.doc.purchase_order
            },
            callback: ({ message }) => {
                if (!message) return;

                // 🔹 1. Set simple fields (EXCLUDE purchase_order)
                let simple_fields = {};

                Object.keys(message).forEach(key => {
                    if (!key.startsWith("table_") && key !== "purchase_order") {
                        simple_fields[key] = message[key];
                    }
                });

                frm.set_value(simple_fields);

                // 🔹 2. Populate child tables
                for (let i = 1; i <= 10; i++) {
                    let table_name = `table_${i}`;
                    frm.clear_table(table_name);

                    (message[table_name] || []).forEach(row => {
                        let child = frm.add_child(table_name);

                        child.item_code = row.item_code ? String(row.item_code) : "";
                        child.item_name = row.item_name || "";
                        child.description = row.description || "";
                        child.qty = row.qty || 0;
                        child.rate = row.rate || 0;
                        child.balance_qty = row.balance_qty || 0;
                        child.amount = row.amount || 0;
                        child.supplier = row.supplier || 0;
                    });

                    frm.refresh_field(table_name);
                }

                frm.refresh();
            }
        });
    },

    purchase_order(frm) {
        if (frm.doc.purchase_order) {
            frm.trigger("grv");
        }
    }
});

// 🔹 Global tracker to prevent alert spam
if (!window.grv_alerts) window.grv_alerts = {};

frappe.ui.form.on("GRV", {
    onload: frm => update_status(frm),
    refresh: frm => update_status(frm),
    validate: frm => update_status(frm)
});

// 1️⃣ ATTACH CHILD DOCTYPE EVENTS (ONLY ONCE - OUTSIDE THE LOOP)
frappe.ui.form.on("Maintainance Type GRV", {
    balance_qty: frm => update_status(frm),
    received_qty: frm => update_status(frm),
    qty: frm => update_status(frm),

    add_qty: function(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        if (!row) return;

        const alert_key = `${cdn}_no_bal`;

        // 🛑 Prevent Spam Alerts
        if (flt(row.balance_qty) <= 0) {
            if (!window.grv_alerts[alert_key]) {
                frappe.msgprint({
                    title: __('No balance left'),
                    message: __(`Item <b>${row.item_code}</b> has no remaining balance.`),
                    indicator: 'red'
                });
                window.grv_alerts[alert_key] = true;
                setTimeout(() => { delete window.grv_alerts[alert_key]; }, 3000);
            }
            return;
        }

        // 🔹 Create Dialog (Now only triggers ONCE)
        const d = new frappe.ui.Dialog({
            title: __("Edit Item: {0}", [row.item_code]),
            fields: [
                { label: "Item Code", fieldname: "item_code", fieldtype: "Data", default: row.item_code, read_only: 1 },
                { label: "Balance Left", fieldname: "balance_qty", fieldtype: "Float", default: row.balance_qty, read_only: 1 },
                { label: "Qty to Add", fieldname: "qty", fieldtype: "Float", default: 1, reqd: 1 }
            ],
            primary_action_label: "Save and Submit",
            primary_action(values) {
                if (flt(values.qty) > flt(row.balance_qty)) {
                    frappe.msgprint({ title: __('Invalid Qty'), message: __('Cannot exceed balance!'), indicator: 'red' });
                    return;
                }

                frappe.call({
                    method: "vehicle.vehicle.doctype.grv.grv.process_grv_item",
                    args: {
                        item_code: row.item_code,
                        qty: values.qty,
                        purchase_order: frm.doc.purchase_order
                    },
                    callback: function(r) {
                        if (r.message && r.message.success) {
                            frappe.model.set_value(cdt, cdn, {
                                "balance_qty": flt(row.balance_qty) - flt(values.qty),
                                "received_qty": flt(row.received_qty || 0) + flt(values.qty),
                                "submitted": 1
                            });

                            d.hide();
                            update_status(frm); 
                            frm.save_or_update();
                            frappe.show_alert({message: __('Success'), indicator: 'green'});
                        } else {
                            frappe.msgprint(__('Error: ') + (r.message?.msg || 'Failed'));
                        }
                    }
                });
            }
        });
        d.show();
    }
});

// 2️⃣ ATTACH PARENT TABLE EVENTS (THE LOOP IS FOR FIELDNAMES ONLY)
const child_tables = ["table_1","table_2","table_3","table_4","table_5","table_6","table_7","table_8","table_9","table_10"];

child_tables.forEach(table_field => {
    frappe.ui.form.on("GRV", {
        [`${table_field}_add`]: frm => update_status(frm),
        [`${table_field}_remove`]: frm => update_status(frm)
    });
});

// 3️⃣ STATUS LOGIC
function update_status(frm) {
    let has_balance = false;
    let any_items_exist = false;

    for (let table_field of child_tables) {
        let rows = frm.doc[table_field] || [];
        if (rows.length > 0) {
            any_items_exist = true;
            if (rows.some(r => flt(r.balance_qty) > 0)) {
                has_balance = true;
                break; 
            }
        }
    }

    if (!any_items_exist) return;

    const new_status = has_balance ? "Partial Received" : "Total Received";
    if (frm.doc.grv_status !== new_status) {
        frm.set_value("grv_status", new_status);
    }
}

frappe.ui.form.on('Maintainance Type', {
    qty: trigger_all,
    rate: trigger_all,
    buying_price: trigger_all,

    refresh: function(frm) {
        calculate_totals(frm);
    }
});

function trigger_all(frm, cdt, cdn) {
    calculate_row_amounts(cdt, cdn);
    calculate_totals(frm);
}


// 🔹 ROW LEVEL (for UI display only)
function calculate_row_amounts(cdt, cdn) {
    let row = locals[cdt][cdn];

    let qty = row.qty || 0;
    let rate = row.rate || 0;
    let buying = row.buying_price || 0;

    let amount = qty * rate;
    let buying_amount = qty * buying;

    frappe.model.set_value(cdt, cdn, "amount", amount);
    frappe.model.set_value(cdt, cdn, "buying_amount", buying_amount);
}


// 🔹 TOTALS (REAL SOURCE OF TRUTH)
function calculate_totals(frm) {

    let grand_qty = 0;
    let grand_amount = 0;
    let grand_buying_amount = 0;

    for (let i = 1; i <= 10; i++) {

        let table_name = `table_${i}`;
        let total_qty_field = `task${i}_total_qty`;
        let total_amount_field = `task${i}_total_amount`;
        let total_buying_field = `task${i}_total_buying_amount`;

        let rows = frm.doc[table_name] || [];

        let table_qty = 0;
        let table_amount = 0;
        let table_buying = 0;

        rows.forEach(r => {
            let qty = r.qty || 0;
            let rate = r.rate || 0;
            let buying = r.buying_price || 0;

            // 🔥 ALWAYS compute (don’t trust stored values)
            let amount = qty * rate;
            let buying_amount = qty * buying;

            table_qty += qty;
            table_amount += amount;
            table_buying += buying_amount;
        });

        // 🔹 set per table
        frm.set_value(total_qty_field, table_qty);
        frm.set_value(total_amount_field, table_amount);
        frm.set_value(total_buying_field, table_buying);

        // 🔹 accumulate
        grand_qty += table_qty;
        grand_amount += table_amount;
        grand_buying_amount += table_buying;
    }

    // 🔥 GRAND TOTALS
    frm.set_value("total_quantity", grand_qty);
    frm.set_value("total_amount", grand_amount);
    frm.set_value("total_buying_amount", grand_buying_amount);

    // 🔥 OPTIONAL (boss move)
    // frm.set_value("total_profit", grand_amount - grand_buying_amount);

    frm.refresh_fields();
}

