frappe.ui.form.on('Job Quote', {
    refresh: function(frm) {

        // 🔹 Convert to WIP
        frm.add_custom_button("Convert to WIP", function() {

            if (frm.doc.job_wip) {
                frappe.msgprint("Quote already converted to WIP");
                return;
            }

            if (frm.doc.job_status === "Quotation" && !frm.doc.job_wip) {
                frappe.call({
                    method: "vehicle.api.convert_quote_to_wip",
                    args: {
                        job_quote: frm.doc.name
                    },
                    callback: function(r) {
                        if (!r.exc) {
                            frm.reload_doc();
                            frappe.msgprint("Converted to WIP");
                        }
                    }
                });
            } else {
                frappe.msgprint("Only Quotation can be converted");
            }

        }, __("Actions"));


        // 🔥 Auto Issue All (hide ONLY for Quotation)
        if (frm.doc.status !== "Quotation") {
            frm.add_custom_button("Auto Issue All", function() {

                frappe.call({
                    method: "vehicle.api.auto_issue_all",
                    args: {
                        job_quote: frm.doc.name
                    },
                    callback: function(r) {
                        if (!r.exc) {
                            frm.reload_doc();
                            frappe.msgprint("All items fully issued");
                        }
                    }
                });

            }, __("Actions"));
        }
    }
});

frappe.ui.form.on('Maintainance Type', {
    item_code: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];

        if (row.item_code) {
            frappe.call({
                method: "vehicle.api.get_item_prices", // 🔥 updated method
                args: { item_code: row.item_code },
                callback: function(r) {
                    if (r.message) {
                        let selling = r.message.selling_price || 0;
                        let buying = r.message.buying_price || 0;

                        // 🔹 set values
                        frappe.model.set_value(cdt, cdn, "rate", selling);
                        frappe.model.set_value(cdt, cdn, "buying_price", buying);

                        // 🔥 calculate margin
                        let margin = selling - buying;
                        frappe.model.set_value(cdt, cdn, "margin", margin);
                    }
                }
            });
        }
    },

    // 🔥 recalc margin if user edits manually
    rate: function(frm, cdt, cdn) {
        calculate_margin(cdt, cdn);
    },

    buying_price: function(frm, cdt, cdn) {
        calculate_margin(cdt, cdn);
    }
});

function calculate_margin(cdt, cdn) {
    let row = locals[cdt][cdn];

    let selling = row.rate || 0;
    let buying = row.buying_price || 0;

    let margin = buying ? ((selling - buying) / buying) * 100 : 0;

    frappe.model.set_value(cdt, cdn, "margin", margin);
}

// 🔹 Global tracker to stop multiple alerts per session
if (!window.grv_alerts) window.grv_alerts = {};

frappe.ui.form.on("Maintainance Type GRV", {
    add_qty: function(frm, cdt, cdn) {
        const row = locals[cdt][cdn];
        if (!row) return;

        // 🆔 Create a truly unique key for this row
        const alert_key = `${cdn}_no_bal`;

        // 🛑 1. CHECK BALANCE & PREVENT SPAM
        if (!row.balance_qty || flt(row.balance_qty) <= 0) {
            if (!window.grv_alerts[alert_key]) {
                frappe.msgprint({
                    title: __('No balance left'),
                    message: __(`Item <b>${row.item_code}</b> has no remaining balance.`),
                    indicator: 'red'
                });
                window.grv_alerts[alert_key] = true; // Lock the alert

                // Auto-unlock after 3 seconds so they can click again later if needed
                setTimeout(() => { delete window.grv_alerts[alert_key]; }, 3000);
            }
            return;
        }

        // 🔹 2. CREATE DIALOG
        const d = new frappe.ui.Dialog({
            title: __("Edit Item: {0}", [row.item_code]),
            fields: [
                { label: "Item Code", fieldname: "item_code", fieldtype: "Data", default: row.item_code, read_only: 1 },
                { label: "Balance Left", fieldname: "balance_qty", fieldtype: "Float", default: row.balance_qty, read_only: 1 },
                { label: "Qty to Add", fieldname: "qty", fieldtype: "Float", default: 1, reqd: 1 }
            ],
            primary_action_label: "Save and Submit",
            primary_action(values) {
                if (flt(values.qty) > flt(row.balance_qty)) {
                    frappe.msgprint({
                        title: __('Invalid Quantity'),
                        message: __('Qty cannot exceed balance left! ⚠️'),
                        indicator: 'red'
                    });
                    return;
                }

                // 🔹 3. BACKEND CALL
                frappe.call({
                    method: "vehicle.vehicle.doctype.grv.grv.process_grv_item",
                    args: {
                        item_code: row.item_code,
                        qty: values.qty,
                        purchase_order: frm.doc.purchase_order
                    },
                    callback: function(r) {
                        if (r.message && r.message.success) {
                            // Update locally
                            const new_balance = flt(row.balance_qty) - flt(values.qty);
                            const new_received = flt(row.received_qty || 0) + flt(values.qty);

                            frappe.model.set_value(cdt, cdn, "balance_qty", new_balance);
                            frappe.model.set_value(cdt, cdn, "received_qty", new_received);
                            frappe.model.set_value(cdt, cdn, "submitted", 1);

                            // Close UI
                            d.hide();

                            // 🔥 Recalculate Status & Save
                            update_status(frm);
                            frm.save_or_update();

                            frappe.show_alert({message: __('Row updated successfully! 🔥'), indicator: 'green'});
                        } else {
                            frappe.msgprint(__('Error processing item: ') + (r.message?.msg || 'Unknown error'));
                        }
                    }
                });
            }
        });

        d.show();
    }
});

// 🔹 4. MULTI-TABLE STATUS UPDATER (The "table_1" to "table_10" logic)
function update_status(frm) {
    const child_tables = ["table_1","table_2","table_3","table_4","table_5","table_6","table_7","table_8","table_9","table_10"];
    let has_balance = false;

    for (let table_field of child_tables) {
        let rows = frm.doc[table_field] || [];
        if (rows.some(r => flt(r.balance_qty) > 0)) {
            has_balance = true;
            break; 
        }
    }

    const new_status = has_balance ? "Partial Received" : "Total Received";
    if (frm.doc.grv_status !== new_status) {
        frm.set_value("status", new_status);
    }
}
